import express, { Request, Response } from 'express';
import { getRepository } from 'typeorm';
import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn } from 'typeorm';

@Entity('products')
export class Product {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  name: string;

  @Column('text')
  description: string;

  @Column('decimal', { precision: 10, scale: 2 })
  price: number;

  @Column()
  category: string;

  @Column()
  brand: string;

  @Column('int')
  stock: number;

  @Column({ default: true })
  active: boolean;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}

const app = express();
app.use(express.json());

app.get('/api/products/search', async (req: Request, res: Response) => {
  try {
    const {
      name,
      category,
      brand,
      minPrice,
      maxPrice,
      minStock,
      inStock,
      sortBy,
      sortOrder,
      limit,
      offset
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT * FROM products WHERE 1=1`;

    if (name) {
      query += ` AND name LIKE '%${name}%'`;
    }

    if (category) {
      query += ` AND category = '${category}'`;
    }

    if (brand) {
      query += ` AND brand = '${brand}'`;
    }

    if (minPrice) {
      query += ` AND price >= ${minPrice}`;
    }

    if (maxPrice) {
      query += ` AND price <= ${maxPrice}`;
    }

    if (minStock) {
      query += ` AND stock >= ${minStock}`;
    }

    if (inStock === 'true') {
      query += ` AND stock > 0`;
    }

    query += ` AND active = true`;

    if (sortBy) {
      const order = sortOrder === 'desc' ? 'DESC' : 'ASC';
      query += ` ORDER BY ${sortBy} ${order}`;
    } else {
      query += ` ORDER BY createdAt DESC`;
    }

    if (limit) {
      query += ` LIMIT ${limit}`;
    }

    if (offset) {
      query += ` OFFSET ${offset}`;
    }

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });

  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error searching products',
      error: error.message
    });
  }
});

app.get('/api/products/advanced-search', async (req: Request, res: Response) => {
  try {
    const {
      searchTerm,
      categories,
      brands,
      priceRange,
      rating,
      tags
    } = req.query;

    const productRepository = getRepository(Product);

    let query = `SELECT * FROM products WHERE active = true`;

    if (searchTerm) {
      query += ` AND (name LIKE '%${searchTerm}%' OR description LIKE '%${searchTerm}%')`;
    }

    if (categories) {
      const categoryList = String(categories).split(',').map(c => `'${c}'`).join(',');
      query += ` AND category IN (${categoryList})`;
    }

    if (brands) {
      const brandList = String(brands).split(',').map(b => `'${b}'`).join(',');
      query += ` AND brand IN (${brandList})`;
    }

    if (priceRange) {
      const [min, max] = String(priceRange).split('-');
      query += ` AND price BETWEEN ${min} AND ${max}`;
    }

    if (rating) {
      query += ` AND rating >= ${rating}`;
    }

    if (tags) {
      const tagList = String(tags).split(',');
      tagList.forEach(tag => {
        query += ` AND tags LIKE '%${tag}%'`;
      });
    }

    query += ` ORDER BY createdAt DESC`;

    const products = await productRepository.query(query);

    res.json({
      success: true,
      count: products.length,
      data: products
    });

  } catch (error) {
    res.status(500).json({
      success: false,
      message: 'Error in advanced search',
      error: error.message
    });
  }
});

